var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【기록-001】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS007M0000-02：<color=#ffd34c>【記録-001】 検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【Record-001】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【記錄-001】 討論會議</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"추가 자료는 모두 확인했네.","JPN":"追加資料はすべて確認した。","ENG":"I've checked all of the additional material.","TWN":"追加資料我已經全部確認過了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"주변인들 증언으로는 이쪽 업계에 뛰어들 사람 같지 않았네만.......","JPN":"周辺人物の証言だと、この業界に入ってくるようなタイプではないようだが……","ENG":"According to the testimonies, she doesn't seem like a person who would join this industry...","TWN":"根據她身邊的人的證言，不太像是會進入我們這個業界的樣子……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무슨 계기라도 있는 건가?","JPN":"何かきっかけでもあったのか？","ENG":"Did something happen to her?","TWN":"難道是有什麼契機？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"주변에는 잘 알려지지 않았지만, 가족 문제가 있는 모양입니다.","JPN":"周りにはよく知られていないようですが、家庭に問題があったようです。","ENG":"Not many people know about this, but she has a family issue.","TWN":"她身旁的人都不太知道，不過好像是因為家庭問題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보고 대상의 <color=#ffd34c>언니</color>가 현재 침식 재난자로 분류되어 구호 시설에 입원 중입니다.","JPN":"報告対象の<color=#ffd34c>姉</color>が現在、侵食災害者に分類されており、救護施設に入院中です。","ENG":"The subject's <color=#ffd34c>sister</color> is currently hospitalized at a relief facility after being classified as a Corruption victim.","TWN":"報告對象的<color=#ffd34c>姐姐</color>是侵蝕受害者，並且正在住院中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>언니</color>라......","JPN":"<color=#ffd34c>姉</color>か……","ENG":"Her <color=#ffd34c>sister</color>?","TWN":"<color=#ffd34c>姐姐</color>啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"중증 환자로 분류되어 치료를 받고 있더군요.","JPN":"重症患者として分離され、治療を受けているそうです。","ENG":"She is currently under intensive care.","TWN":"她被判定為重症患者，正在接受治療。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"진료 기록을 봐서는 현 상태를 유지하는 것도 보통 일이 아닙니다.","JPN":"診療記録を見ると、現状を維持するのも大変なようですね。","ENG":"According to her medical records, it'd be difficult to even maintain her current status.","TWN":"從診療記錄來看，她要維持現狀也不是一件容易的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그것 때문에 보고 대상은 대부분의 수입을 언니의 치료비로 사용하고 있는 상황입니다.","JPN":"そのせいで報告対象は、収入の大半を姉の治療費に充てている状況です。","ENG":"For this reason, most of the subject's income is being used for her sister's treatments.","TWN":"所以報告對象的大部分的收入，都用在姐姐的醫療費上了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"금융 거래 기록에 병원비 지출이 많은 게 그것 때문이었군.","JPN":"金融取引記録に病院が多いのはそのせいだったのか。","ENG":"So that's why her financial records showed a lot of medical expenses.","TWN":"她的交易記錄中有很多醫院費用支出，原來是因為這個啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"작전 보고서에 수당이나 인센티브 어쩌고 하는 이야기가 많아 보이던데 같은 이유겠지?","JPN":"作戦報告書に手当てやインセンティブに関する話が多いのも、そのためなのだな？","ENG":"Is that also why she's mentioned a lot about extra pay or incentives in her operation reports?","TWN":"作戰報告書上提到很多關於津貼或獎勵的事情，也是因為同樣的理由吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그렇겠죠. 그래서 제 위장 상태가 말이 아닙니다.","JPN":"……そうだと思われます。そのせいで私の胃腸にも影響が出ています。","ENG":"I assume so. And it's giving me a stomach ache.","TWN":"……應該是吧？所以我的胃腸開始不舒服了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 생각났는데 말씀하셨던 추가 자금 수혈은 대체 언제쯤......","JPN":"ところで、おっしゃっていた追加資金の方はいつ頃……","ENG":"Speaking of which, when are you planning to invest the extra money you talked about?","TWN":"話說我突然想起來一件事，您說的追加資金什麼時候才能……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠! 크흠!","JPN":"ゴホン！　ゴホン！","ENG":"Ahem! Ahem!","TWN":"咳咳！咳咳！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그나저나 이 <color=#ffd34c>언니</color>라는 사람은 어쩌다 침식 재난자가 된 건가?","JPN":"それより、この<color=#ffd34c>姉</color>という人物は、なぜ侵食災害者となったのだ？","ENG":"Anyway, how did her <color=#ffd34c>sister</color> end up a Corruption victim?","TWN":"先不說那個，她那個<color=#ffd34c>姐姐</color>，是偶然遇到侵蝕災害的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......공식적으로는 시가지에서 발생한 급성 침식 현상에 휘말렸다고 합니다.","JPN":"……市街地で発生した急性侵食現象に巻き込まれたとあります。","ENG":"Official reports indicate that she was caught up in the acute Counterside Effect that occurred in the city.","TWN":"……官方說法，是被捲入了市區發生的急性侵蝕現象。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당시 보충수업 중이던 인근의 학교와 주변 마을까지 초토화시킨 큰 사건이었습니다.","JPN":"当時、補習授業中だった近くの学校と周辺の町が壊滅的被害を受けた大きな事件でした。","ENG":"It was a big incident that devastated the nearby town, including a school where supplementary classes were being held at the time.","TWN":"當時正在輔修的學校附近和周圍的村莊全都化成了焦土，事情非常嚴重。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"자세한 경위는 별첨한 부록을 참고해 주십시오.","JPN":"詳しい経緯は、別添の資料をご参照ください。","ENG":"Please refer to the attached appendix for details.","TWN":"詳細經過請參考附錄。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알겠네. 나중에 천천히 살펴보도록 하지.","JPN":"わかった。後ほどゆっくり確認させてもらおう。","ENG":"Very well. I will take a closer look later.","TWN":"好，我之後再慢慢看。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만...... 안정지대인 재건도시에서 발생할 만한 사건은 아닌 것 같군.","JPN":"しかし……、安全地帯である再建都市で発生するような事件ではないな。","ENG":"But... It doesn't seem like an incident that would occur inside a stabilized rebuilt city.","TWN":"但是……這事件似乎不該發生在是為安定地區的重建都市。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네도 짐작하고 있겠지만 이건 아마도......","JPN":"君も気付いているかもしれないが、これはおそらく……","ENG":"You probably noticed, but this is...","TWN":"你應該也做了一些猜測，但這恐怕是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......묵비권을 행사하겠습니다.","JPN":"……あえて何も言いません。","ENG":"I won't say anything.","TWN":"……請容我行使緘默權。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"확실하지 않은 일에 대해 입을 다무는 건 자네의 장점이자 단점이지.","JPN":"不確実なことに対して口を閉じるのは、君の長所でもあり短所でもあるな。","ENG":"You always spare your breath on uncertain matters. That's both your strength and weakness.","TWN":"對不確定的事情保持沉默，既是你的優點也是你的缺點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 이번 경우에는 그럴 수만도 없지 않겠나?","JPN":"しかし、今回はあり得ると思うのだ。","ENG":"But you can't just remain silent on this case.","TWN":"難道這次也要這樣嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"적어도 감상만이라도 말해 줬으면 하는데?","JPN":"感想だけでもいいから、聞かせてくれないか？","ENG":"Could you at least tell me your opinion?","TWN":"至少告訴我你的感想吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"악취미라고 말해 두겠습니다.","JPN":"悪趣味とだけ言っておきましょう。","ENG":"I'd say the mastermind behind this incident really has a bad taste.","TWN":"我會說你這是惡趣味。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"악취미라.......","JPN":"悪趣味か……","ENG":"A bad taste?","TWN":"惡趣味喔……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그거 정말 어울리는군.","JPN":"実にしっくりくる言葉だな。","ENG":"I agree. I can find no other words to describe it.","TWN":"還真適合我呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};